+    if (keyDataLength == (CFIndex)cckem_pubkey_nbytes_info(cckem_kyber768())) {
+        info = cckem_kyber768();
+    } else if (keyDataLength == (CFIndex)cckem_pubkey_nbytes_info(cckem_kyber1024())) {
+        info = cckem_kyber1024();
