+			   | kSecCSSignGenerateEntitlementDER);
+
+	SecPointer<SecCodeSignerRemote> signer = new SecCodeSignerRemote(flags, signingCertificateChain);
+	signer->parameters(parameters);
+	CodeSigning::Required(signerRef) = signer->handle();
+	END_CSAPI_ERRORS
+}
